"use client";

import { useState } from 'react';
import styles from './checkout.module.scss'; // Use a specific SCSS file
import Image from 'next/image';
import Link from 'next/link'; // Import Link
import { ChangeEvent } from 'react';

// Placeholder data - Replace with API calls or context
const product = {
    name: "Tecno Pova 6 (8GB/256GB) - Xám",
    price: 5690000, // VND
    originalPrice: 6490000,
    imageUrl: "/images/tecno_pova_6.jpg", // Replace with actual path
    quantity: 2,
};

const initialCustomerInfo = {
    name: "Huy Hoàng",
    email: "hoanghuy171031@gmail.com",
    phone: "0939206174",
    subscribe: false,
};

const shippingOptions = [
    { id: "pickup", label: "Nhận tại cửa hàng" },
    { id: "delivery", label: "Giao hàng tận nơi" },
];

const initialShippingAddress = {
    name: "Huy Hoàng", // Or get from customer info
    phone: "0939206174", // Or get from customer info
    city: "",
    district: "",
    ward: "",
    address: "", // Street address
};

interface ProductType {
    name: string;
    price: number;
    originalPrice?: number;
    imageUrl: string;
    quantity: number;
}

interface CustomerInfoType {
    name: string;
    email: string;
    phone: string;
    subscribe: boolean;
}

interface ShippingAddressType {
    name: string;
    phone: string;
    city: string;
    district: string;
    ward: string;
    address: string;
}

interface ShippingOptionType {
    id: string;
    label: string;
}

interface InformationStepProps {
    product: ProductType;
    customerInfo: CustomerInfoType;
    setCustomerInfo: React.Dispatch<React.SetStateAction<CustomerInfoType>>;
    shippingOption: string;
    setShippingOption: React.Dispatch<React.SetStateAction<string>>;
    shippingAddress: ShippingAddressType;
    setShippingAddress: React.Dispatch<React.SetStateAction<ShippingAddressType>>;
    shippingOptions: ShippingOptionType[];
}

interface DeliveryAddressFormProps {
    shippingAddress: ShippingAddressType;
    setShippingAddress: React.Dispatch<React.SetStateAction<ShippingAddressType>>;
    onChange: (e: ChangeEvent<HTMLInputElement | HTMLSelectElement>) => void;
}

interface PaymentStepProps {
    totalPrice: number;
}


export default function Home() {
    const [step, setStep] = useState<number>(1); // 1: Info, 2: Payment
    const [customerInfo, setCustomerInfo] = useState<CustomerInfoType>(initialCustomerInfo);
    const [shippingOption, setShippingOption] = useState<string>(shippingOptions[0].id); // Default to pickup
    const [shippingAddress, setShippingAddress] = useState<ShippingAddressType>(initialShippingAddress);
    const [voucherCode, setVoucherCode] = useState<string>("");
    const [agreeTerms, setAgreeTerms] = useState<boolean>(false);

    const totalPrice = product.price * product.quantity; // Example calculation

    const handleNext = () => {
        setStep((prev: number) => prev + 1);
    };

    const handleBack = () => {
        setStep((prev: number) => prev - 1);
    };

    const renderStepContent = () => {
        switch (step) {
            case 1:
                return (
                    <InformationStep
                        product={product}
                        customerInfo={customerInfo}
                        setCustomerInfo={setCustomerInfo}
                        shippingOption={shippingOption}
                        setShippingOption={setShippingOption}
                        shippingAddress={shippingAddress}
                        setShippingAddress={setShippingAddress}
                        shippingOptions={shippingOptions}
                    />
                );
            case 2:
                return <PaymentStep
                           totalPrice={totalPrice}
                         />;
            default:
                return null;
        }
    };

    return (
        <div className={styles.checkoutContainer}>
            <div className={styles.header}>
                <Link href="/">
                  <button>
                    ← {/* Left arrow character */}
                    </button>
                </Link>
                <span>Thông tin</span>
            </div>

            <div className={styles.steps}>
                <div className={`${styles.step} ${step === 1 ? styles.active : ""}`}>1. Thông Tin</div>
                <div className={`${styles.step} ${step === 2 ? styles.active : ""}`}>2. Thanh Toán</div>
            </div>

            {renderStepContent()}

            <div className={styles.footer}>
                {step > 1 && (
                    <button className={styles.backButton} onClick={handleBack}>
                        Quay Lại
                    </button>
                )}
                {step < 2 && (
                    <button className={styles.continueButton} onClick={handleNext}>
                        Tiếp Tục
                    </button>
                )}
                {step === 2 && (
                    <button className={styles.payButton}>Thanh Toán</button> // Adjust styling
                )}
            </div>
        </div>
    );
}

// -----------------------------------------------------------------------------
// Information Step Component
function InformationStep({
    product,
    customerInfo,
    setCustomerInfo,
    shippingOption,
    setShippingOption,
    shippingAddress,
    setShippingAddress,
    shippingOptions,
}: InformationStepProps) {

    const handleCustomerInfoChange = (e: ChangeEvent<HTMLInputElement>) => {
        const { name, value, type } = e.target;
        const checked = (e.target as HTMLInputElement).checked;

        setCustomerInfo(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value,
        }));
    };

    const handleShippingOptionChange = (e: ChangeEvent<HTMLInputElement>) => {
        setShippingOption(e.target.value);
    };

    const handleShippingAddressChange = (e: ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
      const { name, value } = e.target;
      setShippingAddress(prev => ({
          ...prev,
          [name]:  value,
      }));
    };

  return (
    <div className={styles.informationStep}>
      {/* Product Details */}
      <div className={styles.productDetails}>
        <Image src={product.imageUrl} alt={product.name} width={80} height={80} />
        <div>
          <div className={styles.productName}>{product.name}</div>
          <div className={styles.productPrice}>
            {product.price.toLocaleString("vi-VN", {
              style: "currency",
              currency: "VND",
            })}
            {product.originalPrice && (
              <span className={styles.originalPrice}>
                {product.originalPrice.toLocaleString("vi-VN", {
                  style: "currency",
                  currency: "VND",
                })}
              </span>
            )}
          </div>
        </div>
        <div className={styles.quantity}>Số lượng: {product.quantity}</div>
      </div>

      {/* Customer Information */}
      <div className={styles.customerInfo}>
        <h3>Thông tin khách hàng</h3>
        <div className={styles.formGroup}>
          <label htmlFor="name">Tên:</label>
          <input
            type="text"
            id="name"
            name="name"
            value={customerInfo.name}
            onChange={handleCustomerInfoChange}
          />
        </div>
        <div className={styles.formGroup}>
          <label htmlFor="email">Email:</label>
          <input
            type="email"
            id="email"
            name="email"
            value={customerInfo.email}
            onChange={handleCustomerInfoChange}
          />
        </div>
        <div className={styles.formGroup}>
          <label htmlFor="phone">Số điện thoại:</label>
          <input
            type="tel"
            id="phone"
            name="phone"
            value={customerInfo.phone}
            onChange={handleCustomerInfoChange}
          />
        </div>
        <div className={styles.formGroup}>
          <label htmlFor="subscribe">
            <input
              type="checkbox"
              id="subscribe"
              name="subscribe"
              checked={customerInfo.subscribe}
              onChange={handleCustomerInfoChange}
            />
            Nhận email thông báo và ưu đãi từ CellphoneS
          </label>
        </div>
      </div>

      {/* Shipping Information */}
      <div className={styles.shippingInfo}>
        <h3>Thông tin nhận hàng</h3>
        <div className={styles.shippingOptions}>
          {shippingOptions.map((option: ShippingOptionType) => (
            <label key={option.id} className={styles.shippingOption}>
              <input
                type="radio"
                name="shippingOption"
                value={option.id}
                checked={shippingOption === option.id}
                onChange={handleShippingOptionChange}
              />
              {option.label}
            </label>
          ))}
        </div>

            {shippingOption === 'delivery' ? (
              <DeliveryAddressForm
                shippingAddress={shippingAddress}
                setShippingAddress={setShippingAddress}
                onChange={handleShippingAddressChange}
              />
            ) : (
              <PickupLocationForm /> // Placeholder
            )}
      </div>
    </div>
  );
}

// -----------------------------------------------------------------------------
// Delivery Address Form Component
function DeliveryAddressForm({ shippingAddress, setShippingAddress, onChange }: DeliveryAddressFormProps) {
  // City, District, Ward options - replace with your data
  const cities = ["Hồ Chí Minh", "Hà Nội"];
  const districts = ["Quận 1", "Quận 2", "Quận 3"]; // Based on selected city
  const wards = ["Phường A", "Phường B", "Phường C"]; // Based on selected district

  return (
    <div className={styles.deliveryAddressForm}>
      <div className={styles.formGroup}>
        <label htmlFor="name">Tên người nhận:</label>
        <input
          type="text"
          id="name"
          name="name"
          value={shippingAddress.name}
          onChange={onChange}
          placeholder="Tên người nhận"
        />
      </div>

      <div className={styles.formGroup}>
        <label htmlFor="phone">SĐT người nhận:</label>
        <input
          type="tel"
          id="phone"
          name="phone"
          value={shippingAddress.phone}
          onChange={onChange}
          placeholder="Số điện thoại"
        />
      </div>

      <div className={styles.formGroup}>
        <label htmlFor="city">Tỉnh/Thành phố:</label>
        <select
          id="city"
          name="city"
          value={shippingAddress.city}
          onChange={onChange}
        >
          <option value="">Chọn tỉnh/thành phố</option>
          {cities.map((city) => (
            <option key={city} value={city}>
              {city}
            </option>
          ))}
        </select>
      </div>

      <div className={styles.formGroup}>
        <label htmlFor="district">Quận/Huyện:</label>
        <select
          id="district"
          name="district"
          value={shippingAddress.district}
          onChange={onChange}
        >
          <option value="">Chọn quận/huyện</option>
          {districts.map((district) => (
            <option key={district} value={district}>
              {district}
            </option>
          ))}
        </select>
      </div>

      <div className={styles.formGroup}>
        <label htmlFor="ward">Phường/Xã:</label>
        <select id="ward" name="ward" value={shippingAddress.ward} onChange={onChange}>
          <option value="">Chọn phường/xã</option>
          {wards.map((ward) => (
            <option key={ward} value={ward}>
              {ward}
            </option>
          ))}
        </select>
      </div>

      <div className={styles.formGroup}>
        <label htmlFor="address">Số nhà, tên đường:</label>
        <input
          type="text"
          id="address"
          name="address"
          value={shippingAddress.address}
          onChange={onChange}
          placeholder="Số nhà, tên đường"
        />
      </div>
    </div>
  );
}

